import { Command, flags } from '@heroku-cli/command';
import * as color from '@heroku/heroku-cli-util/color';
import { Args, ux } from '@oclif/core';
import redisApi from '../../lib/redis/api.js';
const wait = (ms) => new Promise(resolve => {
    setTimeout(resolve, ms);
});
export default class Wait extends Command {
    static args = {
        database: Args.string({ description: 'name of the Key-Value Store database. If omitted, it defaults to the primary database associated with the app.', required: false }),
    };
    static description = 'wait for Redis instance to be available';
    static flags = {
        app: flags.app({ required: true }),
        remote: flags.remote(),
        'wait-interval': flags.string({ description: 'how frequently to poll in seconds' }),
    };
    static topic = 'redis';
    async run() {
        const { args, flags } = await this.parse(Wait);
        const { app, 'wait-interval': waitInterval } = flags;
        const { database } = args;
        const api = redisApi(app, database, false, this.heroku);
        const addon = await api.getRedisAddon();
        const waitFor = async () => {
            let interval = waitInterval && Number.parseInt(waitInterval, 10);
            if (!interval || interval < 0)
                interval = 5;
            let status;
            let waiting = false;
            while (true) {
                try {
                    status = await api.request(`/redis/v0/databases/${addon.name}/wait`).then(response => response.body);
                }
                catch (error) {
                    const httpError = error;
                    if (httpError.statusCode !== 404)
                        throw httpError;
                    status = { message: 'not found', 'waiting?': true };
                }
                if (!status['waiting?']) {
                    if (waiting) {
                        ux.action.stop(status.message);
                    }
                    return;
                }
                if (!waiting) {
                    waiting = true;
                    ux.action.start(`Waiting for database ${color.datastore(addon.name)}`, status.message);
                }
                ux.action.status = status.message;
                await wait(interval * 1000);
            }
        };
        await waitFor();
    }
}
